const ComicImage: React.FC<{ src: string; sound?: string; desc: string }> = ({ src, sound, desc }) => {
  const [isLoaded, setIsLoaded] = useState(false);
  return (
    <div className="bg-white p-5 rounded-[2rem] border-2 border-[#4a3728] shadow-[10px_10px_0px_rgba(74,55,40,0.1)] transition-transform hover:rotate-0 transform rotate-[-0.5deg]">
      <div className="relative aspect-[4/3] rounded-2xl overflow-hidden mb-4 border-2 border-[#4a3728]/10 bg-[#f0e6d2] shadow-inner group">
        {!isLoaded && (
          <div className="absolute inset-0 flex items-center justify-center text-[#4a3728]/20 animate-pulse">
            <Loader2 className="w-8 h-8 animate-spin" />
          </div>
        )}
        <div className="absolute inset-0 z-10 opacity-20 pointer-events-none mix-blend-multiply bg-[url('https://www.transparenttextures.com/patterns/handmade-paper.png')]"></div>
        <img 
          src={src} 
          alt="Comic" 
          onLoad={() => setIsLoaded(true)}
          className={`w-full h-full object-cover transition-opacity duration-700 ${isLoaded ? 'opacity-100' : 'opacity-0'}`} 
        />
        {isLoaded && sound && (
          <motion.div 
            initial={{ y: 20, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
