      </div>
    </div>
  );
};

const CapybaraComicApp: React.FC<{ isOpen: boolean; onClose: () => void }> = ({ isOpen, onClose }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const activeChapter = COMIC_CHAPTERS[currentIdx];

  const getAiInsight = async (chapter: Chapter) => {
    setIsAiLoading(true);
    setAiInsight(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `你是一位温和的国学老师。请针对互动漫画《我的卡皮巴拉》第${chapter.id + 1}章：“${chapter.title}”的情节（大纲：${chapter.summary}），为孩子写一段30字以内的温馨成长启发。`,
      });
      setAiInsight(response.text);
    } catch (e) {
      setAiInsight("愿每一个好习惯，都像魔法一样守护着你。");
    } finally {
      setIsAiLoading(false);
    }
  };

  useEffect(() => {
    if (isOpen) {
      getAiInsight(activeChapter);
    }
  }, [currentIdx, isOpen]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-[#FDF6E3] flex flex-col font-sans overflow-hidden">
      <div className="absolute inset-0 opacity-[0.05] pointer-events-none z-0 bg-[url('https://www.transparenttextures.com/patterns/cream-paper.png')]"></div>

      <header className="relative z-10 px-6 pt-12 pb-6 flex flex-col items-center shrink-0">
        <div className="w-full max-w-4xl flex justify-between items-end mb-4">
          <button onClick={onClose} className="p-3 bg-white border-2 border-[#4a3728] rounded-2xl shadow-[4px_4px_0px_#4a3728] active:translate-x-1 active:translate-y-1 active:shadow-none transition-all">
            <X size={20} className="text-[#4a3728]" />
          </button>

          <div className="flex flex-col items-end">
            <div className="flex items-center gap-2 text-[#4a3728] font-black text-[10px] mb-2 uppercase tracking-widest">
              <Trophy size={14} className="text-orange-500" />
              <span>成长魔法值</span>
              <span className="text-orange-600">{activeChapter.growth}%</span>
            </div>
            <div className="w-48 sm:w-64 h-4 bg-white border-2 border-[#4a3728] rounded-full p-1 shadow-inner overflow-hidden">
              <motion.div 
                initial={{ width: 0 }}
                animate={{ width: `${activeChapter.growth}%` }}
                className="h-full bg-gradient-to-r from-orange-400 to-amber-500 rounded-full"
              />
            </div>
            <p className="text-[9px] text-[#4a3728]/40 mt-1 font-bold italic">{activeChapter.tip}</p>
          </div>
        </div>
        <h1 className="text-4xl md:text-5xl font-black text-[#4a3728] serif-font italic tracking-tighter">我的卡皮巴拉</h1>
      </header>

      <main className="flex-1 overflow-y-auto no-scrollbar px-6 pb-24 relative z-10">
        <div className="max-w-5xl mx-auto py-8 flex flex-col lg:flex-row gap-12">

          {/* 漫画主展示区 */}
