              <div className="absolute top-1/2 left-0 right-0 h-px bg-[#4a3728]/10 -z-10"></div>
              <motion.h2 
                key={activeChapter.title}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className="text-2xl font-bold text-[#4a3728] bg-[#FDF6E3] inline-block px-8 py-2 border-x-2 border-[#4a3728]/20 serif-font"
