import React from 'react';
import { AppItem } from '../types';
import { MoreHorizontal } from 'lucide-react';
import { motion } from 'framer-motion';

interface AppCardProps {
  item: AppItem;
  onClick: (item: AppItem) => void;
}

const AppCard: React.FC<AppCardProps> = ({ item, onClick }) => {
  // 核心视觉映射：根据图标功能匹配参考图中的配色方案
  const getTheme = () => {
    const icon = item.icon || 'auto_awesome_motion';

    // 蓝色系 (地理、天文、语言、波) -> 匹配 3D地球
    if (['public', 'language', 'waves', 'translate', 'explore', 'map'].includes(icon)) {
      return { bg: 'bg-[#B0BEC5] dark:bg-[#546E7A]', iconColor: 'text-white/80' };
    }
    // 黄色系 (逻辑、数学、创意) -> 匹配 逻辑思维
    if (['lightbulb', 'calculate', 'functions', 'psychology', 'brain', 'schedule'].includes(icon)) {
      return { bg: 'bg-[#FFE082] dark:bg-[#D4AF37]/40', iconColor: 'text-yellow-700/60 dark:text-yellow-200/60' };
    }
    // 绿色系 (科学、生物、国学、艺术) -> 匹配 微观世界/三字经
    if (['science', 'pest_control', 'eco', 'menu_book', 'auto_stories', 'import_contacts', 'history_edu', 'palette', 'spellcheck'].includes(icon)) {
      return { bg: 'bg-[#A5D6A7] dark:bg-[#2E7D32]/40', iconColor: 'text-green-700/60 dark:text-green-200/60' };
    }

    // 默认莫兰迪蓝灰色
    return { bg: 'bg-[#9EB3C2] dark:bg-[#455A64]', iconColor: 'text-white/80' };
  };

  const theme = getTheme();

  return (
    /* Fix: Cast motion props to any to bypass TypeScript error */
    <motion.div 
      {...({
        initial: { opacity: 0, y: 10 },
        whileInView: { opacity: 1, y: 0 },
        viewport: { once: true },
        whileTap: { scale: 0.98 }
      } as any)}
      className="group relative bg-white dark:bg-dark-card rounded-ios overflow-hidden border border-morandi-border dark:border-white/5 soft-shadow transition-all hover:bg-white dark:hover:bg-[#252529] cursor-pointer mb-4"
      onClick={() => onClick(item)}
    >
      <div className="flex p-5 gap-6 items-center">
        {/* iOS 风格图标容器 */}
        <div className={`w-20 h-20 md:w-24 md:h-24 flex-shrink-0 rounded-[1.8rem] flex items-center justify-center shadow-sm relative overflow-hidden ${theme.bg}`}>
          {/* 背景装饰 */}
          <div className="absolute inset-0 bg-gradient-to-br from-white/10 to-transparent opacity-50"></div>

          <span className={`material-icons-outlined text-4xl md:text-5xl relative z-10 ${theme.iconColor}`}>
            {item.icon || 'auto_awesome_motion'}
          </span>

          {/* 装饰圆圈 */}
          <div className="absolute w-12 h-12 border border-white/10 rounded-full -top-2 -right-2"></div>
          <div className="absolute w-20 h-[1px] bg-white/10 top-1/2 left-2 rotate-45"></div>
        </div>

        {/* 右侧信息 */}
        <div className="flex-1 min-w-0">
          <div className="flex justify-between items-start mb-1">
            <h4 className="text-lg font-bold text-morandi-charcoal dark:text-slate-100 truncate tracking-tight serif-font">
              {item.title}
            </h4>
            <button className="text-slate-200 dark:text-slate-700 hover:text-morandi-taupe transition-colors">
              <MoreHorizontal size={20} />
            </button>
          </div>
          <p className="text-slate-400 dark:text-slate-500 text-xs leading-relaxed mb-3 font-medium line-clamp-2 italic">
            {item.description}
          </p>
          <div className="flex gap-2">
            <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest bg-slate-50 dark:bg-slate-900/50 text-slate-300 dark:text-slate-600 border border-slate-100 dark:border-white/5`}>
              {item.category.toUpperCase()}
            </span>
