                         <p className="text-lg font-black serif-font text-center">点击汉字探秘</p>
                      </div>
                    )}
                 </motion.div>
               )}

               {activeTab === 'ai' && (
                  /* Fix: Cast motion props to any to bypass TypeScript error */
                  <motion.div 
