const CapybaraComicApp: React.FC<{ isOpen: boolean; onClose: () => void }> = ({ isOpen, onClose }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const activeChapter = COMIC_CHAPTERS[currentIdx];

  const getAiInsight = async (chapter: Chapter) => {
    setIsAiLoading(true);
    setAiInsight(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `你是一位温和的国学老师。请针对互动漫画《我的卡皮巴拉》第${chapter.id + 1}章：“${chapter.title}”的情节（大纲：${chapter.summary}），为孩子写一段30字以内的温馨成长启发。`,
      });
      setAiInsight(response.text);
    } catch (e) {
      setAiInsight("愿每一个好习惯，都像魔法一样守护着你。");
    } finally {
      setIsAiLoading(false);
    }
  };

  useEffect(() => {
    if (isOpen) {
      getAiInsight(activeChapter);
    }
  }, [currentIdx, isOpen]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] bg-[#FDF6E3] flex flex-col font-sans overflow-hidden">
